          <p
            class="p-0 m-0 dolg_value font-weight-bold"
            :style="getDolgStyle(qarzUser.sum)"
          >
            {{ formatNumber(qarzUser.sum) }} <small>сум</small>
          </p>
        </div>
        <div class="dolg_item">
          <p class="p-0 m-0 mb-1 dolg_label">USD</p>
