<script>
import {mdbBtn, mdbIcon} from 'mdbvue'
export default {
  components:{
    mdbBtn, mdbIcon
  },
  data() {
    return {
      hostname: this.$store.state.server_ip,
    }
  },
  props:{
    option:{
      type: Object,
      default() {
        return {}
      }
    },
    qarzUser: {
      type: Object,
      default() {
        return null
      }
    }
  },
  methods:{
    printInfo(){
      this.$emit('printed', this.option)
    },
    getDolgStyle(value){
      const num = parseFloat(value || 0);
      if (num > 0) {
        return { color: '#E7515A' }; // qizil
      } else if (num < 0) {
        return { color: '#009587' }; // yashil
      } else {
        return { color: '#000000' }; // qora
      }
    },
    formatNumber(value) {
      if (value === null || value === undefined || value === '') return '0';
      const num = parseFloat(value);
      if (isNaN(num)) return '0';
      return num
        .toFixed(1)
        .replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ');
    }
  }
}
</script>

